-- link groups -> categories
update public.accounts g set parent_id = c.id from public.accounts c
  where g.entity_id = '11111111-1111-1111-1111-111111111111' and g.type='group' and c.type='category'
    and c.entity_id = g.entity_id and c.code = 'CAT::' || g.category_name;

-- link accounts -> groups
update public.accounts a set parent_id = g.id from public.accounts g
  where a.entity_id = '11111111-1111-1111-1111-111111111111' and a.type='account' and g.type='group'
    and g.entity_id = a.entity_id and g.code = 'GRP::' || a.category_name || '::' || a.group_name;

